## What to do
Consolidate hypercert create and update into a single REST-style route at `/api/certs/route.ts`.

### 1. Create `app/api/certs/route.ts`

**POST handler** (create) ŌĆö move the existing logic from `app/api/certs/create/route.ts` verbatim:
```typescript
export async function POST(req: NextRequest) {
  // Exact same logic as current create/route.ts
  // Parse FormData, build CreateHypercertParams, call ctx.scopedRepo.hypercerts.create()
}
```

**PUT handler** (update):
```typescript
export async function PUT(req: NextRequest) {
  try {
    const formData = await req.formData();
    const ctxPromise = getRepoContext();
    const hypercertUri = formData.get("hypercertUri") as string | null;

    if (!hypercertUri) {
      return NextResponse.json({ error: "Missing hypercertUri" }, { status: 400 });
    }

    const title = formData.get("title") as string | null;
    const shortDescription = formData.get("shortDescription") as string | null;
    const description = formData.get("description") as string | null;
    const startDate = formData.get("startDate") as string | null;
    const endDate = formData.get("endDate") as string | null;
    const imageRaw = formData.get("image");

    const ctx = await ctxPromise;
    if (!ctx) {
      return NextResponse.json({ error: "Could not authenticate repo" }, { status: 401 });
    }

    // Build updates object with only provided fields
    const updates: Record<string, unknown> = {};
    if (title !== null) updates.title = title;
    if (shortDescription !== null) updates.shortDescription = shortDescription;
    if (description !== null) updates.description = description;
    if (startDate !== null) updates.startDate = startDate;
    if (endDate !== null) updates.endDate = endDate;

    // Handle image: File = new image, string "null" = remove, absent = no change
    let image: Blob | null | undefined;
    if (imageRaw instanceof File) {
      image = imageRaw;
    } else if (imageRaw === "null") {
      image = null;
    }

    const data = await ctx.scopedRepo.hypercerts.update({
      uri: hypercertUri,
      updates,
      image,
    });
    return NextResponse.json(data);
  } catch (e) {
    console.error("Error updating hypercert:", e);
    return NextResponse.json(
      { error: `Failed to update hypercert: ${e instanceof Error ? e.message : String(e)}` },
      { status: 500 }
    );
  }
}
```

