```tsx
const needsResolution = contributors
  .filter((c) => c.needsResolution && c.identityRef)
  .map((c) => ({
    contributor: c,
    parsed: parseAtUri(c.identityRef!.uri),
  }))
  .filter((item): item is { contributor: DisplayContributor; parsed: NonNullable<ReturnType<typeof parseAtUri>> } =>
    item.parsed !== undefined
