// Then in useQueries:
queries: needsResolution.map(({ contributor, parsed }) => ({
  queryKey: queryKeys.hypercerts.contributorInformation(parsed.did, parsed.rkey),
  queryFn: () => getContributorInformationRecord(parsed),
