import { NodeOAuthClient, JoseKey } from '@atproto/oauth-client-node';
import { buildClientMetadata, config, OAUTH_SCOPE } from './config';
import {
  RedisSessionStore,
  RedisStateStore,
  RedisEpdsStateStore,
} from './redis-state-store';

export const sessionStore = new RedisSessionStore();
export const stateStore = new RedisStateStore();
export const epdsStateStore = new RedisEpdsStateStore();

export { OAUTH_SCOPE };

const clientMetadata = buildClientMetadata();

const oauthClient = new NodeOAuthClient({
  clientMetadata,
  stateStore,
  sessionStore,
  handleResolver: config.handleResolver,
  // keyset is needed for non-loopback (production) clients that use private_key_jwt
  // For loopback, token_endpoint_auth_method is 'none' so keyset is optional
  ...(config.jwkPrivate ? {
    keyset: [await JoseKey.fromJWK(JSON.parse(config.jwkPrivate))],
  } : {}),
});

export default oauthClient;
```

### Key differences from the SDK wrapper:
- `NodeOAuthClient` has `.authorize(handle)` ŌåÆ returns `URL` (not string). The login route will need to call `.toString()` or use the URL directly.
- `NodeOAuthClient` has `.callback(params)` ŌåÆ returns `{ session: OAuthSession, state: string | null }`. The callback route currently expects just the session ŌĆö it will need to destructure.
- `NodeOAuthClient` has `.restore(did)` ŌåÆ returns `OAuthSession` (same as SDK's `restoreSession`).
- `NodeOAuthClient` has `.revoke(did)` ŌåÆ same as SDK's `revokeSession`.
- There is NO `.repository()` method ŌĆö that was SDK-specific and will be handled in later phases.
- There is NO `.resolveSessionPds()` ŌĆö that will be handled in a separate task.

### Top-level await
The `JoseKey.fromJWK()` call is async. Since this is a module-level singleton, use top-level await. Next.js supports this in server modules. If there are issues, wrap in a lazy initialization pattern:
```ts
let _client: NodeOAuthClient | null = null;
export async function getOAuthClient(): Promise<NodeOAuthClient> {
  if (!_client) {
    _client = new NodeOAuthClient({ ... });
  }
  return _client;
}
```
Prefer the top-level await approach first. Only fall back to lazy init if build fails.

### Important: JoseKey import
`JoseKey` is re-exported from `@atproto/oauth-client-node` (it re-exports from `@atproto/jwk-jose`). Check the actual export name ŌĆö it might be `JoseKey` or might need to be imported differently. Run: `grep -r 'JoseKey\|fromJWK' node_modules/@atproto/oauth-client-node/dist/` to confirm.

