    return pdsUrl.endsWith('/') ? pdsUrl.slice(0, -1) : pdsUrl;
  } catch (error) {
    console.warn('Failed to resolve PDS URL from session, falling back to CDN:', error);
    return 'https://cdn.bsky.app';
  }
}
```

### Why we need per-session PDS resolution:
Users can log in from any PDS (e.g., bsky.social, climateai.org). Their data lives on their PDS, not necessarily on NEXT_PUBLIC_PDS_URL. The `issuer` is the authorization server ŌĆö the `aud` (audience) is the resource server (PDS) where the user's repo actually lives.

### How to get it:
`OAuthSession` has `getTokenInfo()` which returns `TokenInfo` containing `aud: string` ŌĆö this is the PDS URL (resource server).

```ts
type TokenInfo = {
  expiresAt?: Date;
  expired?: boolean;
  scope: AtprotoOAuthScope;
  iss: string;   // authorization server
  aud: string;   // resource server (PDS) ŌåÉ this is what we want
  sub: AtprotoDid;
};
```

### New implementation:
```ts
import 'server-only';
import type { OAuthSession } from '@atproto/oauth-client-node';

export async function resolveSessionPds(session: OAuthSession): Promise<string> {
  try {
    const tokenInfo = await session.getTokenInfo();
    const pdsUrl = tokenInfo.aud;
    return pdsUrl.endsWith('/') ? pdsUrl.slice(0, -1) : pdsUrl;
  } catch (error) {
    console.warn('Failed to resolve PDS URL from session, falling back to CDN:', error);
    return 'https://cdn.bsky.app';
  }
}
```

