## What to do
Add four new server actions for managing repository collaborators (editors). These wrap the SDK's `collaborators` API. All actions must check that the repo context is SDS-capable before calling collaborator methods.

### 1. `listEditors(params: { repoDid: string })`
```typescript
export const listEditors = async (params: { repoDid: string }) => {
  const ctx = await getRepoContext({ targetDid: params.repoDid });
  if (!ctx) {
    throw new Error("listEditors failed: could not establish repository context.");
  }
  if (!ctx.isSDS) {
    // PDS repos don't support collaborators ŌĆö return empty list
    return { collaborators: [], cursor: undefined };
  }
  return ctx.scopedRepo.collaborators.list();
};
```

### 2. `grantEditorAccess(params: GrantAccessParams)`
Uses the existing `GrantAccessParams` interface (already defined on line 11-15).
```typescript
export const grantEditorAccess = async (params: GrantAccessParams) => {
  const ctx = await getRepoContext({ targetDid: params.repoDid });
  if (!ctx) {
    throw new Error("grantEditorAccess failed: could not establish repository context.");
  }
  if (!ctx.isSDS) {
    throw new Error("grantEditorAccess failed: editor management requires a Shared Data Server (SDS).");
  }
  if (ctx.activeDid !== params.repoDid) {
    throw new Error("grantEditorAccess failed: Forbidden ŌĆö you can only manage editors on your own repository.");
  }
  return ctx.scopedRepo.collaborators.grant({
    userDid: params.userDid,
    role: params.role,
  });
};
```

### 3. `revokeEditorAccess(params: { repoDid: string; userDid: string })`
```typescript
export const revokeEditorAccess = async (params: { repoDid: string; userDid: string }) => {
  const ctx = await getRepoContext({ targetDid: params.repoDid });
  if (!ctx) {
    throw new Error("revokeEditorAccess failed: could not establish repository context.");
  }
  if (!ctx.isSDS) {
    throw new Error("revokeEditorAccess failed: editor management requires a Shared Data Server (SDS).");
  }
  if (ctx.activeDid !== params.repoDid) {
    throw new Error("revokeEditorAccess failed: Forbidden ŌĆö you can only manage editors on your own repository.");
  }
  return ctx.scopedRepo.collaborators.revoke({ userDid: params.userDid });
};
