## What to do
Create React Query hooks for listing, granting, and revoking editor access. These wrap the server actions from create-actions.ts.

### 1. Create `queries/hypercerts/use-editors-query.ts`

```typescript
"use client";

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import {
  listEditors,
  grantEditorAccess,
  revokeEditorAccess,
} from "@/lib/create-actions";
import type { RepositoryRole } from "@hypercerts-org/sdk-core";

// Query key factory
const editorKeys = {
  all: ["editors"] as const,
  list: (repoDid: string) => [...editorKeys.all, "list", repoDid] as const,
};

/**
 * Query hook to list editors (collaborators) for a repository.
 * Returns empty list when on PDS (non-SDS).
 */
export function useEditorsQuery(repoDid: string | undefined) {
  return useQuery({
    queryKey: editorKeys.list(repoDid ?? ""),
    queryFn: () => listEditors({ repoDid: repoDid! }),
    enabled: !!repoDid,
  });
}

/**
 * Mutation hook to grant editor access to a user.
 */
export function useGrantEditorMutation(options?: {
  onSuccess?: () => void;
}) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (params: { repoDid: string; userDid: string; role: RepositoryRole }) =>
      grantEditorAccess(params),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({
        queryKey: editorKeys.list(variables.repoDid),
      });
      toast.success("Editor access granted!");
      options?.onSuccess?.();
    },
    onError: (error) => {
      console.error("Grant editor error:", error);
      toast.error(
        error instanceof Error ? error.message : "Failed to grant editor access."
      );
    },
  });
}

/**
 * Mutation hook to revoke editor access from a user.
 */
export function useRevokeEditorMutation(options?: {
  onSuccess?: () => void;
}) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (params: { repoDid: string; userDid: string }) =>
      revokeEditorAccess(params),
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({
        queryKey: editorKeys.list(variables.repoDid),
      });
      toast.success("Editor access revoked.");
      options?.onSuccess?.();
    },
    onError: (error) => {
      console.error("Revoke editor error:", error);
      toast.error(
        error instanceof Error ? error.message : "Failed to revoke editor access."
      );
    },
  });
}
```

